sql:
SELECT property_type, houses_sold, average_days_on_market
FROM sales_statistics
WHERE borough_code = '1' AND date = '1995-01-01';

SELECT AVG(average_price) AS avg_property_price
FROM average_prices
WHERE borough_code = 'E09000001';

SELECT AVG(average_days_on_market) AS avg_days_on_market
FROM sales_statistics
WHERE borough_code = '1';

SELECT average_price
FROM average_prices
WHERE borough_code = '0' AND date = '1995-02-01';

SELECT AVG(average_price) AS avg_price
FROM real_estate_data
WHERE area = 'City of London' AND property_type = 'apartment';

external_knowledge:
- Above-average crime rates refer to rates higher than the overall average crime rate across all boroughs; 
- Below-average property prices refer to prices lower than the overall average property price across all boroughs;
- Crime rate per capita is calculated as total crimes divided by population.
